/**
 * Menu Flow Integration Tests
 *
 * Integration tests for the menu flow covering:
 * - Complete menu creation → category → product flow
 * - Menu CRUD operations
 * - Publishing and unpublishing menus
 * - Category management within menus
 * - Product management within categories
 * - Multi-tenant data isolation
 *
 * These tests verify the interaction between MenuService,
 * CategoryService, ProductService, and related components.
 *
 * @module tests/integration/menu.integration.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import { MenuService } from '@/modules/menu/menu.service';
import { CategoryService } from '@/modules/menu/category.service';
import { ProductService } from '@/modules/menu/product.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { EventService } from '@/core/services/event.service';
import type {
  Menu,
  MenuWithRelations,
  Category,
  CategoryWithRelations,
  Product,
  ProductWithRelations,
  CreateMenuRequest,
  CreateCategoryRequest,
  CreateProductRequest,
  MenuSettings,
} from '@/modules/menu/menu.types';
import type { MenuRepository, PaginatedResult } from '@/modules/menu/menu.repository';
import type { CategoryRepository } from '@/modules/menu/category.repository';
import type { ProductRepository } from '@/modules/menu/product.repository';

// -----------------------------------------------------------------------------
// Test Utilities & Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock MenuRepository
 */
function createMockMenuRepository(): Record<string, Mock> {
  return {
    findAll: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findBySlug: vi.fn(),
    findDefaultMenu: vi.fn(),
    findPublished: vi.fn(),
    slugExists: vi.fn(),
    count: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    updateSettings: vi.fn(),
    publish: vi.fn(),
    unpublish: vi.fn(),
    setAsDefault: vi.fn(),
    duplicate: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
  };
}

/**
 * Creates a mock CategoryRepository
 */
function createMockCategoryRepository(): Record<string, Mock> {
  return {
    findAll: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findBySlug: vi.fn(),
    findByMenuId: vi.fn(),
    slugExists: vi.fn(),
    count: vi.fn(),
    countAll: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    reorder: vi.fn(),
    moveToParent: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
  };
}

/**
 * Creates a mock ProductRepository
 */
function createMockProductRepository(): Record<string, Mock> {
  return {
    findAll: vi.fn(),
    findAllWithRelations: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findBySlug: vi.fn(),
    findByCategoryId: vi.fn(),
    findFeatured: vi.fn(),
    slugExists: vi.fn(),
    count: vi.fn(),
    create: vi.fn(),
    createWithRelations: vi.fn(),
    update: vi.fn(),
    reorder: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
    findVariants: vi.fn(),
    createVariant: vi.fn(),
    updateVariant: vi.fn(),
    deleteVariant: vi.fn(),
    setDefaultVariant: vi.fn(),
    findModifiers: vi.fn(),
    createModifier: vi.fn(),
    updateModifier: vi.fn(),
    deleteModifier: vi.fn(),
    setAllergens: vi.fn(),
    addAllergen: vi.fn(),
    removeAllergen: vi.fn(),
    findNutritionInfo: vi.fn(),
    upsertNutritionInfo: vi.fn(),
    deleteNutritionInfo: vi.fn(),
  };
}

/**
 * Creates a mock EventService that tracks emitted events
 */
function createMockEventService(): {
  emitCustom: Mock;
  getEmittedEvents: () => Array<{ event: string; data: unknown }>;
} {
  const emittedEvents: Array<{ event: string; data: unknown }> = [];

  return {
    emitCustom: vi.fn().mockImplementation(async (event: string, data: unknown) => {
      emittedEvents.push({ event, data });
    }),
    getEmittedEvents: () => [...emittedEvents],
  };
}

/**
 * Creates a mock menu for testing
 */
function createMockMenu(overrides: Partial<Menu> = {}): Menu {
  return {
    id: 'menu_integration_test',
    organizationId: 'org_integration_test',
    branchId: null,
    themeId: null,
    name: 'Integration Test Menu',
    slug: 'integration-test-menu',
    description: 'A menu for integration testing',
    isPublished: false,
    isDefault: true,
    publishedAt: null,
    settings: {} as MenuSettings,
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock menu with relations
 */
function createMockMenuWithRelations(
  overrides: Partial<MenuWithRelations> = {}
): MenuWithRelations {
  return {
    ...createMockMenu(),
    theme: null,
    categories: [],
    qrCodes: [],
    ...overrides,
  };
}

/**
 * Creates a mock category for testing
 */
function createMockCategory(overrides: Partial<Category> = {}): Category {
  return {
    id: 'cat_integration_test',
    organizationId: 'org_integration_test',
    menuId: 'menu_integration_test',
    parentId: null,
    name: 'Integration Test Category',
    slug: 'integration-test-category',
    description: 'A category for integration testing',
    image: null,
    isActive: true,
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock category with relations
 */
function createMockCategoryWithRelations(
  overrides: Partial<CategoryWithRelations> = {}
): CategoryWithRelations {
  return {
    ...createMockCategory(),
    parent: null,
    children: [],
    products: [],
    ...overrides,
  };
}

/**
 * Creates a mock product for testing
 */
function createMockProduct(overrides: Partial<Product> = {}): Product {
  return {
    id: 'prod_integration_test',
    organizationId: 'org_integration_test',
    categoryId: 'cat_integration_test',
    name: 'Integration Test Product',
    slug: 'integration-test-product',
    description: 'A product for integration testing',
    shortDescription: 'Test product',
    basePrice: 150,
    currency: 'TRY',
    image: null,
    gallery: [],
    isActive: true,
    isAvailable: true,
    isFeatured: false,
    isChefRecommended: false,
    preparationTime: null,
    calories: null,
    spicyLevel: null,
    tags: [],
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock product with relations
 */
function createMockProductWithRelations(
  overrides: Partial<ProductWithRelations> = {}
): ProductWithRelations {
  return {
    ...createMockProduct(),
    category: undefined,
    variants: [],
    modifiers: [],
    allergens: [],
    nutritionInfo: null,
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Integration Test Suite
// -----------------------------------------------------------------------------

describe('Menu Flow Integration', () => {
  let menuService: MenuService;
  let categoryService: CategoryService;
  let productService: ProductService;
  let mockMenuRepository: ReturnType<typeof createMockMenuRepository>;
  let mockCategoryRepository: ReturnType<typeof createMockCategoryRepository>;
  let mockProductRepository: ReturnType<typeof createMockProductRepository>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  const orgId = 'org_integration_test';

  beforeEach(() => {
    // Create fresh mocks for each test
    mockMenuRepository = createMockMenuRepository();
    mockCategoryRepository = createMockCategoryRepository();
    mockProductRepository = createMockProductRepository();
    mockEventService = createMockEventService();

    // Create service instances with mocks
    menuService = new MenuService(
      mockMenuRepository as unknown as MenuRepository,
      mockEventService as unknown as EventService
    );

    categoryService = new CategoryService(
      mockCategoryRepository as unknown as CategoryRepository,
      mockMenuRepository as unknown as MenuRepository,
      mockEventService as unknown as EventService
    );

    productService = new ProductService(
      mockProductRepository as unknown as ProductRepository,
      mockCategoryRepository as unknown as CategoryRepository,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // Complete Menu Creation → Category → Product Flow
  // ---------------------------------------------------------------------------

  describe('Complete Menu Flow: Create Menu → Category → Product', () => {
    it('should complete full menu creation lifecycle', async () => {
      // STEP 1: Create a new menu
      const createMenuData: CreateMenuRequest = {
        name: 'Lunch Menu',
        description: 'Our delicious lunch offerings',
      };

      // Setup mocks for menu creation
      mockMenuRepository.count.mockResolvedValue(0); // First menu
      mockMenuRepository.slugExists.mockResolvedValue(false);
      const createdMenu = createMockMenu({
        name: createMenuData.name,
        description: createMenuData.description,
        slug: 'lunch-menu',
        isDefault: true,
      });
      mockMenuRepository.create.mockResolvedValue(createdMenu);

      const menuResult = await menuService.create(orgId, createMenuData);

      // Verify menu creation
      expect(menuResult.menu).toBeDefined();
      expect(menuResult.menu.name).toBe('Lunch Menu');
      expect(menuResult.menu.isDefault).toBe(true); // First menu should be default
      expect(menuResult.message).toContain('successfully');

      // Verify menu creation event
      const menuEvents = mockEventService.getEmittedEvents();
      expect(menuEvents.some((e) => e.event === 'menu.created')).toBe(true);

      // STEP 2: Add a category to the menu
      const createCategoryData: CreateCategoryRequest = {
        menuId: createdMenu.id,
        name: 'Appetizers',
        description: 'Start your meal right',
      };

      // Setup mocks for category creation
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createdMenu);
      mockCategoryRepository.slugExists.mockResolvedValue(false);
      const createdCategory = createMockCategory({
        menuId: createdMenu.id,
        name: createCategoryData.name,
        description: createCategoryData.description,
        slug: 'appetizers',
      });
      mockCategoryRepository.create.mockResolvedValue(createdCategory);

      const categoryResult = await categoryService.create(orgId, createCategoryData);

      // Verify category creation
      expect(categoryResult.category).toBeDefined();
      expect(categoryResult.category.name).toBe('Appetizers');
      expect(categoryResult.category.menuId).toBe(createdMenu.id);
      expect(categoryResult.message).toContain('successfully');

      // Verify category creation event
      const categoryEvents = mockEventService.getEmittedEvents();
      expect(categoryEvents.some((e) => e.event === 'category.created')).toBe(true);

      // STEP 3: Add a product to the category
      const createProductData: CreateProductRequest = {
        categoryId: createdCategory.id,
        name: 'Spring Rolls',
        basePrice: 45,
        description: 'Crispy vegetable spring rolls',
        isActive: true,
        variants: [
          { name: 'Regular (3 pcs)', price: 45 },
          { name: 'Large (5 pcs)', price: 65 },
        ],
        modifiers: [
          { name: 'Extra dipping sauce', price: 5 },
        ],
      };

      // Setup mocks for product creation
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(createdCategory);
      mockProductRepository.slugExists.mockResolvedValue(false);
      const createdProduct = createMockProductWithRelations({
        categoryId: createdCategory.id,
        name: createProductData.name,
        basePrice: createProductData.basePrice,
        description: createProductData.description,
        slug: 'spring-rolls',
        variants: [
          {
            id: 'var_1',
            productId: 'prod_integration_test',
            name: 'Regular (3 pcs)',
            price: 45,
            isDefault: false,
            isAvailable: true,
            sortOrder: 0,
            createdAt: new Date(),
            updatedAt: new Date(),
          },
          {
            id: 'var_2',
            productId: 'prod_integration_test',
            name: 'Large (5 pcs)',
            price: 65,
            isDefault: false,
            isAvailable: true,
            sortOrder: 1,
            createdAt: new Date(),
            updatedAt: new Date(),
          },
        ],
        modifiers: [
          {
            id: 'mod_1',
            productId: 'prod_integration_test',
            name: 'Extra dipping sauce',
            price: 5,
            isDefault: false,
            isRequired: false,
            maxQuantity: 1,
            sortOrder: 0,
            createdAt: new Date(),
            updatedAt: new Date(),
          },
        ],
      });
      mockProductRepository.createWithRelations.mockResolvedValue(createdProduct);

      const productResult = await productService.create(orgId, createProductData);

      // Verify product creation
      expect(productResult.product).toBeDefined();
      expect(productResult.product.name).toBe('Spring Rolls');
      expect(productResult.product.categoryId).toBe(createdCategory.id);
      expect(productResult.product.variants).toHaveLength(2);
      expect(productResult.product.modifiers).toHaveLength(1);
      expect(productResult.message).toContain('successfully');

      // Verify product creation event
      const productEvents = mockEventService.getEmittedEvents();
      expect(productEvents.some((e) => e.event === 'product.created')).toBe(true);

      // STEP 4: Publish the menu
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(createdMenu);
      const publishedMenu = createMockMenu({
        ...createdMenu,
        isPublished: true,
        publishedAt: new Date(),
      });
      mockMenuRepository.publish.mockResolvedValue(publishedMenu);

      const publishResult = await menuService.publish(orgId, createdMenu.id);

      // Verify menu publish
      expect(publishResult.menu.isPublished).toBe(true);
      expect(publishResult.message).toContain('successfully');

      // Verify publish event
      const publishEvents = mockEventService.getEmittedEvents();
      expect(publishEvents.some((e) => e.event === 'menu.published')).toBe(true);
    });

    it('should maintain referential integrity through the flow', async () => {
      // Create menu
      const menu = createMockMenu({ id: 'menu_ref_test' });
      mockMenuRepository.count.mockResolvedValue(0);
      mockMenuRepository.slugExists.mockResolvedValue(false);
      mockMenuRepository.create.mockResolvedValue(menu);

      await menuService.create(orgId, { name: 'Test Menu' });

      // Create category linked to menu
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(menu);
      const category = createMockCategory({
        id: 'cat_ref_test',
        menuId: menu.id,
      });
      mockCategoryRepository.slugExists.mockResolvedValue(false);
      mockCategoryRepository.create.mockResolvedValue(category);

      const categoryResult = await categoryService.create(orgId, {
        menuId: menu.id,
        name: 'Test Category',
      });

      // Verify category is linked to correct menu
      expect(categoryResult.category.menuId).toBe(menu.id);

      // Create product linked to category
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(category);
      const product = createMockProductWithRelations({
        id: 'prod_ref_test',
        categoryId: category.id,
      });
      mockProductRepository.slugExists.mockResolvedValue(false);
      mockProductRepository.createWithRelations.mockResolvedValue(product);

      const productResult = await productService.create(orgId, {
        categoryId: category.id,
        name: 'Test Product',
        basePrice: 100,
      });

      // Verify product is linked to correct category
      expect(productResult.product.categoryId).toBe(category.id);
    });
  });

  // ---------------------------------------------------------------------------
  // Menu CRUD Operations
  // ---------------------------------------------------------------------------

  describe('Menu CRUD Operations', () => {
    it('should create multiple menus with unique slugs', async () => {
      // First menu
      mockMenuRepository.count.mockResolvedValue(0);
      mockMenuRepository.slugExists.mockResolvedValue(false);
      const menu1 = createMockMenu({ id: 'menu_1', name: 'Lunch Menu' });
      mockMenuRepository.create.mockResolvedValue(menu1);

      const result1 = await menuService.create(orgId, { name: 'Lunch Menu' });
      expect(result1.menu.isDefault).toBe(true); // First menu is default

      // Second menu
      mockMenuRepository.count.mockResolvedValue(1);
      mockMenuRepository.slugExists.mockResolvedValue(false);
      const menu2 = createMockMenu({
        id: 'menu_2',
        name: 'Dinner Menu',
        isDefault: false,
      });
      mockMenuRepository.create.mockResolvedValue(menu2);

      const result2 = await menuService.create(orgId, { name: 'Dinner Menu' });
      expect(result2.menu.isDefault).toBe(false); // Second menu is not default

      // Verify two menus created events
      const events = mockEventService.getEmittedEvents();
      const menuCreatedEvents = events.filter((e) => e.event === 'menu.created');
      expect(menuCreatedEvents).toHaveLength(2);
    });

    it('should generate unique slug when duplicate exists', async () => {
      mockMenuRepository.count.mockResolvedValue(1);
      mockMenuRepository.slugExists
        .mockResolvedValueOnce(true)  // 'lunch-menu' exists
        .mockResolvedValueOnce(false); // 'lunch-menu-1' is available

      const menu = createMockMenu({ slug: 'lunch-menu-1' });
      mockMenuRepository.create.mockResolvedValue(menu);

      await menuService.create(orgId, { name: 'Lunch Menu' });

      // Verify create was called with the generated unique slug
      expect(mockMenuRepository.create).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ slug: 'lunch-menu-1' })
      );
    });

    it('should update menu successfully', async () => {
      const existingMenu = createMockMenu();
      const updatedMenu = createMockMenu({
        name: 'Updated Menu Name',
        description: 'Updated description',
      });

      mockMenuRepository.findByIdOrThrow.mockResolvedValue(existingMenu);
      mockMenuRepository.update.mockResolvedValue(updatedMenu);

      const result = await menuService.update(orgId, existingMenu.id, {
        name: 'Updated Menu Name',
        description: 'Updated description',
      });

      expect(result.menu.name).toBe('Updated Menu Name');
      expect(result.message).toContain('successfully');

      // Verify update event
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'menu.updated')).toBe(true);
    });

    it('should duplicate menu successfully', async () => {
      const originalMenu = createMockMenu({ id: 'menu_original' });
      const duplicatedMenu = createMockMenu({
        id: 'menu_duplicate',
        name: 'Copy of Integration Test Menu',
        slug: 'copy-of-integration-test-menu',
        isDefault: false,
        isPublished: false,
      });

      mockMenuRepository.findByIdOrThrow.mockResolvedValue(originalMenu);
      mockMenuRepository.slugExists.mockResolvedValue(false);
      mockMenuRepository.duplicate.mockResolvedValue(duplicatedMenu);

      const result = await menuService.duplicate(
        orgId,
        originalMenu.id,
        'Copy of Integration Test Menu'
      );

      expect(result.menu.id).not.toBe(originalMenu.id);
      expect(result.menu.isDefault).toBe(false);
      expect(result.menu.isPublished).toBe(false);
      expect(result.message).toContain('successfully');
    });
  });

  // ---------------------------------------------------------------------------
  // Menu Publishing Flow
  // ---------------------------------------------------------------------------

  describe('Menu Publishing Flow', () => {
    it('should publish and unpublish menu', async () => {
      const unpublishedMenu = createMockMenu({ isPublished: false });
      const publishedMenu = createMockMenu({
        isPublished: true,
        publishedAt: new Date(),
      });

      // Publish
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(unpublishedMenu);
      mockMenuRepository.publish.mockResolvedValue(publishedMenu);

      const publishResult = await menuService.publish(orgId, unpublishedMenu.id);
      expect(publishResult.menu.isPublished).toBe(true);

      // Verify publish event
      let events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'menu.published')).toBe(true);

      // Unpublish
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(publishedMenu);
      mockMenuRepository.unpublish.mockResolvedValue(unpublishedMenu);

      const unpublishResult = await menuService.unpublish(orgId, publishedMenu.id);
      expect(unpublishResult.menu.isPublished).toBe(false);

      // Verify unpublish event
      events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'menu.unpublished')).toBe(true);
    });

    it('should not republish already published menu', async () => {
      const publishedMenu = createMockMenu({
        isPublished: true,
        publishedAt: new Date(),
      });

      mockMenuRepository.findByIdOrThrow.mockResolvedValue(publishedMenu);

      const result = await menuService.publish(orgId, publishedMenu.id);

      expect(result.message).toContain('already published');
      expect(mockMenuRepository.publish).not.toHaveBeenCalled();
    });

    it('should not unpublish already unpublished menu', async () => {
      const unpublishedMenu = createMockMenu({ isPublished: false });

      mockMenuRepository.findByIdOrThrow.mockResolvedValue(unpublishedMenu);

      const result = await menuService.unpublish(orgId, unpublishedMenu.id);

      expect(result.message).toContain('not published');
      expect(mockMenuRepository.unpublish).not.toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Category Management
  // ---------------------------------------------------------------------------

  describe('Category Management', () => {
    it('should create nested categories (parent/child)', async () => {
      const menu = createMockMenu();
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(menu);

      // Create parent category
      const parentCategory = createMockCategory({
        id: 'cat_parent',
        name: 'Main Courses',
        parentId: null,
      });
      mockCategoryRepository.slugExists.mockResolvedValue(false);
      mockCategoryRepository.create.mockResolvedValue(parentCategory);

      const parentResult = await categoryService.create(orgId, {
        menuId: menu.id,
        name: 'Main Courses',
      });

      expect(parentResult.category.parentId).toBeNull();

      // Create child category
      mockCategoryRepository.findById.mockResolvedValue(parentCategory);
      const childCategory = createMockCategory({
        id: 'cat_child',
        name: 'Grilled',
        parentId: parentCategory.id,
      });
      mockCategoryRepository.create.mockResolvedValue(childCategory);

      const childResult = await categoryService.create(orgId, {
        menuId: menu.id,
        name: 'Grilled',
        parentId: parentCategory.id,
      });

      expect(childResult.category.parentId).toBe(parentCategory.id);
    });

    it('should prevent parent from different menu', async () => {
      const menu1 = createMockMenu({ id: 'menu_1' });
      const menu2 = createMockMenu({ id: 'menu_2' });

      const parentFromOtherMenu = createMockCategory({
        id: 'cat_other',
        menuId: menu2.id, // Different menu
      });

      mockMenuRepository.findByIdOrThrow.mockResolvedValue(menu1);
      mockCategoryRepository.findById.mockResolvedValue(parentFromOtherMenu);

      await expect(
        categoryService.create(orgId, {
          menuId: menu1.id,
          name: 'Child Category',
          parentId: parentFromOtherMenu.id,
        })
      ).rejects.toThrow(AppException);
    });

    it('should reorder categories within menu', async () => {
      const menu = createMockMenu();
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(menu);

      const reorderItems = [
        { id: 'cat_1', sortOrder: 2 },
        { id: 'cat_2', sortOrder: 0 },
        { id: 'cat_3', sortOrder: 1 },
      ];

      mockCategoryRepository.reorder.mockResolvedValue(undefined);

      const result = await categoryService.reorder(orgId, {
        menuId: menu.id,
        items: reorderItems,
      });

      expect(result.count).toBe(3);
      expect(result.message).toContain('successfully');

      // Verify reorder event
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'category.reordered')).toBe(true);
    });

    it('should prevent deleting category with children', async () => {
      const categoryWithChildren = createMockCategoryWithRelations({
        id: 'cat_parent',
        children: [createMockCategory({ id: 'cat_child', parentId: 'cat_parent' })],
      });

      mockCategoryRepository.findByIdWithRelations.mockResolvedValue(categoryWithChildren);

      await expect(
        categoryService.delete(orgId, categoryWithChildren.id)
      ).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Product Management
  // ---------------------------------------------------------------------------

  describe('Product Management', () => {
    it('should create product with variants and modifiers', async () => {
      const category = createMockCategory();
      mockCategoryRepository.findByIdOrThrow.mockResolvedValue(category);
      mockProductRepository.slugExists.mockResolvedValue(false);

      const productWithRelations = createMockProductWithRelations({
        name: 'Burger Deluxe',
        variants: [
          {
            id: 'var_1',
            productId: 'prod_1',
            name: 'Single',
            price: 100,
            isDefault: true,
            isAvailable: true,
            sortOrder: 0,
            createdAt: new Date(),
            updatedAt: new Date(),
          },
          {
            id: 'var_2',
            productId: 'prod_1',
            name: 'Double',
            price: 150,
            isDefault: false,
            isAvailable: true,
            sortOrder: 1,
            createdAt: new Date(),
            updatedAt: new Date(),
          },
        ],
        modifiers: [
          {
            id: 'mod_1',
            productId: 'prod_1',
            name: 'Extra cheese',
            price: 15,
            isDefault: false,
            isRequired: false,
            maxQuantity: 2,
            sortOrder: 0,
            createdAt: new Date(),
            updatedAt: new Date(),
          },
        ],
      });
      mockProductRepository.createWithRelations.mockResolvedValue(productWithRelations);

      const result = await productService.create(orgId, {
        categoryId: category.id,
        name: 'Burger Deluxe',
        basePrice: 100,
        variants: [
          { name: 'Single', price: 100, isDefault: true },
          { name: 'Double', price: 150 },
        ],
        modifiers: [
          { name: 'Extra cheese', price: 15, maxQuantity: 2 },
        ],
      });

      expect(result.product.variants).toHaveLength(2);
