  describe('Soft Delete & Restore', () => {
    it('should soft delete and restore menu', async () => {
      const menu = createMockMenu({ isDefault: false });
      mockMenuRepository.findByIdOrThrow.mockResolvedValue(menu);
      mockMenuRepository.count.mockResolvedValue(2); // Multiple menus exist
      mockMenuRepository.softDelete.mockResolvedValue(undefined);

      // Delete
      await menuService.delete(orgId, menu.id);
      expect(mockMenuRepository.softDelete).toHaveBeenCalledWith(menu.id, orgId);

      // Verify delete event
      let events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'menu.deleted')).toBe(true);

      // Restore
      const restoredMenu = createMockMenu({ ...menu, deletedAt: null });
      mockMenuRepository.restore.mockResolvedValue(restoredMenu);

      const restored = await menuService.restore(orgId, menu.id);
      expect(restored.deletedAt).toBeNull();

      // Verify restore event
      events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'menu.restored')).toBe(true);
    });

    it('should soft delete and restore product', async () => {
      const product = createMockProduct();
      mockProductRepository.findByIdOrThrow.mockResolvedValue(product);
      mockProductRepository.softDelete.mockResolvedValue(undefined);

      // Delete
      await productService.delete(orgId, product.id);
      expect(mockProductRepository.softDelete).toHaveBeenCalledWith(product.id, orgId);

      // Verify delete event
      let events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'product.deleted')).toBe(true);

      // Restore
      const restoredProduct = createMockProduct({ ...product, deletedAt: null });
      mockProductRepository.restore.mockResolvedValue(restoredProduct);

      const restored = await productService.restore(orgId, product.id);
      expect(restored.deletedAt).toBeNull();

      // Verify restore event
      events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'product.restored')).toBe(true);
    });
  });
